def __init__(self, step=None):
    if step:
        self.V, self.E, self.lV, self.lE = step.V.copy(), step.E.copy(), step.lV.copy(), step.lE.copy()
    else:
        self.V, self.E = set(), set()
        self.lV, self.lE = dict(), dict()

    self.hV, self.hE = dict(), dict()

