```python
def role_yaml_parse(role):
    if isinstance(role, string_types):
        name = scm = src = version = None
        if ',' in role:
            if role.count(',') == 1:
                src, version = role.strip().split(',', 1)
            elif role.count(',') == 2:
                src, version, name = role.strip().split(',', 2)
            else:
                raise AnsibleError("Invalid role line (%s). Proper format is 'role_name[,version[,name]]'" % role)
        else:
            src = role

        if name is None:
            name = RoleRequirement.repo_url_to_role_name(src)
        if '+' in src:
            scm, src = src.split('+', 1)

        return dict(name=name, src=src, scm=scm, version=version)

    if 'role' in role:
        name = role['role']
        if ',' in name:
            raise AnsibleError("Invalid old style role requirement: %s" % name)
        else:
            del role['role']
            role['name'] = name
    else:
        role = role.copy()

        if 'src' in role:
            # New style: { src: 'galaxy.role,version,name', other_vars: "here" }
            if 'github.com' in role["src"] and 'http' in role["src"] and '+' not in role["src"] and not role["src"].endswith('.tar.gz'):
                role["src"] = "git+" + role["src"]

            if '+' in role["src"]:
                role["scm"], _, role["src"] = role["src"].partition('+')

            if 'name' not in role:
                role["name"] = RoleRequirement.repo_url_to_role_name(role["src"])

        role.setdefault('version', '')
        role.setdefault('scm', None)

    for key in list(role.keys()):
        if key not in VALID_SPEC_KEYS:
            role.pop(key)

    return role
```

### Refactoring Summary:
- **First Refactoring (Multiple Target Assignment)**: Refactor the block `name = None`, `scm = None`, `src = None`, `version = None` into a single line of assignment: `name = scm = src = version = None`.
- **Second Refactoring (Multiple Target Assignment)**: Shortcut the unpacking of return values by refactoring `(dummy, role["scm"], role["src"])` into skip the dummy discard variable by using `_` in `role["scm"], _, role["src"] = role["src"].partition('+')`.

Thus, **the total number of refactorings = 2**.

